const input = $input.item.json.body;

const prompt = input.prompt || '';
const width = input.width || 1024;
const height = input.height || 1024;
const negativePrompt = input.negative_prompt || 'blurry, low quality, deformed, ugly, bad anatomy, disfigured, poorly drawn face, mutation, extra limb, poorly drawn hands, missing limb, floating limbs, disconnected limbs, malformed hands, blur, out of focus, long neck, long body';
const seed = Math.floor(Math.random() * 2147483647);

const comfyuiUrl = process.env.COMFYUI_URL || 'http://117.50.218.161:8188';

const workflow = {
  "1": { "inputs": { "unet_name": "z_image_turbo_bf16.safetensors", "weight_dtype": "default" }, "class_type": "UNETLoader" },
  "2": { "inputs": { "vae_name": "ae.safetensors" }, "class_type": "VAELoader" },
  "3": { "inputs": { "clip_name": "qwen_3_4b.safetensors", "type": "lumina2", "device": "default" }, "class_type": "CLIPLoader" },
  "4": { "inputs": { "shift": 3, "model": ["1", 0] }, "class_type": "ModelSamplingAuraFlow" },
  "5": { "inputs": { "width": width, "height": height, "batch_size": 1 }, "class_type": "EmptySD3LatentImage" },
  "6": { "inputs": { "text": prompt, "clip": ["3", 0] }, "class_type": "CLIPTextEncode" },
  "7": { "inputs": { "text": negativePrompt, "clip": ["3", 0] }, "class_type": "CLIPTextEncode" },
  "8": { "inputs": { "seed": seed, "steps": 15, "cfg": 1.5, "sampler_name": "euler", "scheduler": "simple", "denoise": 1, "model": ["4", 0], "positive": ["6", 0], "negative": ["7", 0], "latent_image": ["5", 0] }, "class_type": "KSampler" },
  "9": { "inputs": { "samples": ["8", 0], "vae": ["2", 0] }, "class_type": "VAEDecode" },
  "10": { "inputs": { "filename_prefix": "FreeGen", "images": ["9", 0] }, "class_type": "SaveImage" }
};

return {
  comfyui_url: comfyuiUrl,
  comfyui_payload: JSON.stringify(workflow)
};

const response = $input.first()?.json || {};
const promptId = response?.prompt_id || response?.id;
const comfyuiUrl = $input.first()?.json?.comfyui_url || '';

return [{
  json: {
    executionId: promptId,
    comfyuiUrl: comfyuiUrl,
    workflowType: 'image',
    status: 'submitted'
  }
}];
